// This code relies on the ORDER of items coming from the previous node.
// The previous node sets or preserves an index to guarantee that order.
//
// Why this matters:
// - The FIRST time we see a value, we keep it
// - ALL later occurrences are marked as duplicates
// - If item order changes, the WRONG item may be kept
//
// In short: index = priority

// Set used to remember values we have already processed
const seen = new Set();

// n8n processes items in array order: items[0], items[1], items[2], etc.
// The index from the previous node ensures this order is predictable
return items.map(item => {

  // Field used for deduplication
  // Change 'output' if a different field should define uniqueness
  const value = item.json.output;

  // If this value has already been seen earlier in the list
  if (seen.has(value)) {

    // This means another item with the same value
    // appeared at a LOWER index (higher priority)
    // → mark this one as a duplicate for removal downstream
    item.json.duplicate = true;

  } else {

    // This is the FIRST occurrence of this value
    // Because of the controlled index, this is the
    // correct item we want to keep
    item.json.duplicate = false;

    // Store the value so any later items
    // (higher index = lower priority)
    // can be flagged as duplicates
    seen.add(value);
  }

  // Always return the modified item
  return item;
});

/*
  Rebuild full URLs from partial URLs extracted from HTML.

  Handles:
  - Absolute URLs: "https://example.com/x"
  - Protocol-relative: "//example.com/x"
  - Root-relative: "/x"
  - Relative with dot segments: "../x", "../../../x"

  Special case (mount path):
  If the source page is under a sub-path like:
    https://example.com/app/content/page.html
  and a partial URL starts with:
    /content/other.html
  then we treat it as:
    https://example.com/app/content/other.html
*/

// -------------------- Utility helpers --------------------

function stripQuotesAndWhitespace(value) {
  return String(value ?? "")
    .trim()
    .replace(/^['"]+|['"]+$/g, "")
    .trim();
}

function isLikelyFilePath(url) {
  try {
    // If URL() exists, use it (safe)
    const u = new URL(url);
    const lastSegment = u.pathname.split("/").filter(Boolean).pop() || "";
    return /\.[a-z0-9]{1,6}$/i.test(lastSegment);
  } catch {
    // Fallback: simple segment check
    const lastSegment = String(url)
      .split("?")[0]
      .split("#")[0]
      .split("/")
      .filter(Boolean)
      .pop() || "";
    return /\.[a-z0-9]{1,6}$/i.test(lastSegment);
  }
}

function normalizeDoubleSlashes(url) {
  return String(url).replace(/^(https?:\/\/)(.*)$/i, (match, protocol, rest) => {
    return protocol + rest.replace(/\/{2,}/g, "/");
  });
}

function addTrailingSlashIfDirectory(url) {
  if (!url) return url;

  // Trim + remove control chars (e.g., \r) that can break URL parsing
  const s = String(url).replace(/[\u0000-\u001F\u007F]/g, "").trim();
  if (!s) return s;

  // Preserve query/hash while deciding about the path
  const m = s.match(/^([^?#]*)(\?[^#]*)?(#.*)?$/);
  const base = m?.[1] ?? s;
  const query = m?.[2] ?? "";
  const hash  = m?.[3] ?? "";

  // Only operate on absolute http(s) URLs; otherwise leave as-is
  if (!/^https?:\/\//i.test(base)) return s;

  // If base is just the origin (no path), force a trailing slash:
  // https://example.com  -> https://example.com/
  if (/^https?:\/\/[^\/]+$/i.test(base)) return base + "/" + query + hash;

  // If already has trailing slash, keep as-is
  if (base.endsWith("/")) return base + query + hash;

  // Don't add slash to likely files (extensions)
  if (isLikelyFilePath(base)) return base + query + hash;

  // Otherwise add trailing slash (directory-like)
  return base + "/" + query + hash;
}

// Force all absolute http(s) URLs to https
function forceHttps(url) {
  return String(url).replace(/^http:\/\//i, "https://");
}

/*
  Removes "." and ".." segments from a path.
  Example:
    /a/b/../c  -> /a/c
*/
function removeDotSegments(path) {
  const parts = String(path).split("/");
  const out = [];

  for (const part of parts) {
    if (part === "" || part === ".") continue;
    if (part === "..") {
      out.pop();
      continue;
    }
    out.push(part);
  }

  return "/" + out.join("/");
}

// -------------------- URL resolution logic --------------------

function resolveUrl(baseUrl, partialUrl) {
  const rel = stripQuotesAndWhitespace(partialUrl);
  const base = forceHttps(stripQuotesAndWhitespace(baseUrl));

  if (!rel) return "";

  // Absolute URL
  if (/^https?:\/\//i.test(rel)) return forceHttps(rel);

  // Base must be absolute to resolve properly
  if (!/^https?:\/\//i.test(base)) return rel;

  // Protocol-relative URL: force https
  if (rel.startsWith("//")) {
    return "https:" + rel;
  }

  // Extract origin (scheme + host)
  const origin = base.match(/^(https?:\/\/[^\/]+)/i)?.[1] ?? "";

  // Get the base path (no query/hash)
  const basePath = base
    .slice(origin.length)
    .split("?")[0]
    .split("#")[0];

  // Root-relative path
  if (rel.startsWith("/")) {
    // Mount-path heuristic:
    // If basePath looks like "/<mount>/<segment>/..."
    // and rel starts with "/<segment>/..."
    // then return "/<mount>" + rel instead of just rel
    const relFirst = rel.split("/").filter(Boolean)[0];
    const baseSegs = basePath.split("/").filter(Boolean);

    if (relFirst && baseSegs.length >= 2 && baseSegs[1] === relFirst) {
      const mount = baseSegs[0];
      return origin + "/" + mount + rel;
    }

    return origin + rel;
  }

  // Relative path (includes "../" and "../../../")
  // Resolve it against the directory of the base page:
  // baseDir = "/a/b/c/" if basePath is "/a/b/c/page.html"
  const baseDir = basePath.endsWith("/")
    ? basePath
    : basePath.substring(0, basePath.lastIndexOf("/") + 1);

  const combined = baseDir + rel;             // may include ../ segments
  const cleanedPath = removeDotSegments(combined);

  return origin + cleanedPath;
}

// -------------------- n8n execution --------------------

return items.map((item) => {
  const partialUrl = stripQuotesAndWhitespace(item.json.partialUrl ?? item.json.url ?? "");
  const sourceUrl = forceHttps(stripQuotesAndWhitespace(item.json.sourceUrl ?? ""));
  const domain = forceHttps(stripQuotesAndWhitespace(item.json.domain ?? ""));

  let outputUrl = "";

  // Prefer resolving against the full page URL
  if (partialUrl && sourceUrl) {
    outputUrl = resolveUrl(sourceUrl, partialUrl);
  }
  // Fallback: resolve against a domain if provided
  else if (partialUrl && domain) {
    outputUrl = resolveUrl(domain, partialUrl);
  }
  // Last resort: return the partial string
  else {
    outputUrl = partialUrl;
  }

  // Normalize and make directory URLs consistent
  outputUrl = normalizeDoubleSlashes(outputUrl);
  outputUrl = addTrailingSlashIfDirectory(outputUrl);

  // Final hard stop: do not let http through
  outputUrl = forceHttps(outputUrl);

  return {
    json: {
      ...item.json,
      output: outputUrl,
    },
  };
});

