return items.map(item => {
  let md = item.json.body || '';

  // Normalize line endings
  md = md.replace(/\r\n/g, '\n');

  const navJunkPatterns = [
    /you are here:/i,
    /back to top/i,
    /cookie/i,
    /privacy policy/i,
    /terms of (use|service)/i,
    /all rights reserved/i,
    /accept cookies/i,
    /enable javascript/i,
  ];

  const lines = md.split('\n');
  const cleanedLines = [];

  for (let raw of lines) {
    let line = raw;
    const trimmed = line.trim();

    // 1. Keep blank lines (we'll collapse later)
    if (!trimmed) {
      cleanedLines.push('');
      continue;
    }

    // 2. Drop YAML/frontmatter / horizontal rules like "---"
    if (/^---+$/.test(trimmed)) continue;

    // 3. Drop pure punctuation separators (***, ___, etc.)
    if (/^[\-\*_~`]+$/.test(trimmed)) continue;

    // 4. Detect markdown table-ish lines
    const isTableRow = /^\s*\|.*\|\s*$/.test(trimmed);
    const isTableSeparator = /^\s*\|?\s*:?-{2,}.*\|?\s*$/.test(trimmed);

    // If it's clearly a table separator row, drop it
    if (isTableSeparator) continue;

    // Optional: If you want to drop ALL table rows, uncomment:
    // if (isTableRow) continue;

    // 5. Skip obvious nav/footer/legal junk
    if (navJunkPatterns.some(re => re.test(trimmed))) continue;

    // 6. Skip tiny non-heading, non-list UI fragments
    const wordCount = trimmed.split(/\s+/).length;
    const isHeadingOrList = /^(#{1,6}\s|\* |-|\d+\.)/.test(trimmed);
    if (
      wordCount <= 3 &&
      !isHeadingOrList &&
      !/[.!?]$/.test(trimmed) // not a full sentence
    ) {
      // e.g. "Filter:", "Submit Search", "Login"
      continue;
    }

    // 7. Normalize internal spacing a bit
    line = line.replace(/[ \t]{2,}/g, ' ');

    cleanedLines.push(line);
  }

  // 8. Collapse multiple blank lines into a single blank line
  const cleaned = cleanedLines
    .join('\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();

  item.json.cleanedMarkdown = cleaned;
  return item;
});

