/**
 * n8n Code node (JavaScript)
 *
 * Purpose:
 * - Extract likely human-facing page paths from text (item.json.body)
 * - Filter out assets, APIs, tracking, and plumbing URLs
 * - Output one item per valid page path
 */

const items = $input.all();
const output = [];

/**
 * ===============================
 * REGEX DEFINITIONS
 * ===============================
 */

// Find URL-like strings in text
const CANDIDATE_RE =
  /(?:(?:"|')((?:https?:\/\/|\/\/|\/|\.{1,2}\/)[^"' \t\r\n<>]+)(?:"|'))|((?:https?:\/\/|\/\/|\/|\.{1,2}\/)[^\s"'<>]+)/g;

// Accept .html / .htm pages
const PAGE_EXT = /\.(?:html?)(?:[?#]|$)/i;

// Reject static assets
const STATIC_ASSET_EXT =
  /\.(?:js|mjs|cjs|css|map|png|jpe?g|gif|svg|webp|ico|pdf|zip|gz|tar|rar|7z|mp4|mp3|wav|webm|woff2?|ttf|eot)(?:[?#]|$)/i;

// Reject numeric-only paths
const NUMERIC_PATH = /^\/\d+(?:\/\d+)*\/?$/;

// Reject code-like fragments
const CODE_SMELL = /[\[\]\(\)\{\}\\\^\$|]|\\[dDsSwWbBuxpP]/;

// Reject APIs, auth, static dirs, internal routes
const HARD_REJECT =
  /(?:^|\/)(api|apis|service|services|asmx|svc|wsdl|graphql|rest|rpc|oauth|auth|signin|login|logout|token|session|callback|webhook|debug|health|status|metrics|internal|admin|plugins?|scripts?|assets?|static|cdn|media|img|images|fonts?|css|js|ccm|form-data|upload|download)(?:\/|$)/i;

// Reject analytics / tracking keywords
const TRACKING_KEYWORDS =
  /(?:^|[\/?#])(adserver|ads|adservice|adserving|adtrack|adtracking|affiliates?|beacon|banners?|click|clicktrack|clickthrough|clk|conv|conversion|conversions|convert|cvt|collect|collector|event|events|eventhub|eventtrack|eventtracking|impression|impressions|pixel|pixels|tag|tags|tagging|tracker|trackers|tracking|telemetry|analytics|measurement|metrics|stats|stat|log|logger|logging|gtag|gtm|googletagmanager|google-analytics|ga4|urchin|gen_204|doubleclick|ddm|floodlight|activity|fb|facebook|fbevents|meta|mp|tr|pixel_id|tiktok|ttq|snap|snapchat|pinterest|pintrk|linkedin|licdn|insight|segment|analyticsjs|amplitude|mixpanel|mparticle|heap|hotjar|fullstory|clarity)(?:[\/?#]|$)/i;

// Reject known tracking path shapes
const TRACKING_SHAPES =
  /(?:^|\/)(ddm\/activity|g\/collect|collect$|pagead\/|gtag\/js|tr\/|pixel\/)(?:[\/?#]|$)/i;

// Explicit Google Ads reject
const PAGEAD_REJECT = /(?:^|\/)pagead(?:\/|$)/i;

// Reject versioned API routes
const VERSIONED_API_REJECT =
  /^\/(?:v\d+|gm\/v\d+|mms\/v\d+|ctx\/v\d+)(?:\/|$)/i;

// Reject consent / config / ad plumbing
const PLUMBING_REJECT =
  /(?:^|\/)(consent|privacy-manager|vendor-list|choice|consent-status|meta-data|tcfv2|wrapper|openrtb2?|auction|usync|authorize|keys|messages|configuration|config|signals|targeting|schain|bid|ids|get-treatments|treatments|auxia|sampling|record|toolbox|marker|init|listeners|prepend|store)(?:\/|$)/i;

// Reject noisy protocol-relative hosts
const NOISE_HOST_RE =
  /^\/\/(?:c\.amazon-adsystem\.com|ep\d+\.adtrafficquality\.google)\//i;

/**
 * ===============================
 * HELPER FUNCTIONS
 * ===============================
 */

function normalize(s) {
  // Strip punctuation that sticks to URLs
  return s.replace(/[),.;:!?`]+$/, "").replace(/\\+"?$/, "");
}

function isPathOrProtocolRelative(s) {
  return (
    s.startsWith("/") ||
    s.startsWith("./") ||
    s.startsWith("../") ||
    s.startsWith("//")
  );
}

// Allow human-friendly URLs without .html
function looksLikePrettyContent(s) {
  if (!/^\/[a-z0-9][a-z0-9-]+\/[a-z0-9][a-z0-9-]+/i.test(s)) return false;
  if (/[A-Z_+=]/.test(s)) return false;
  if (/\.[a-z0-9]{1,6}(?:[?#]|$)/i.test(s) && !PAGE_EXT.test(s)) return false;
  return true;
}

/**
 * ===============================
 * MAIN LOOP
 * ===============================
 */

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const text = item.json?.body;

  // Skip items without text
  if (!text) continue;

  // Prevent duplicates per input item
  const seen = new Set();

  // Reset regex cursor (important!)
  CANDIDATE_RE.lastIndex = 0;

  let match;
  while ((match = CANDIDATE_RE.exec(text)) !== null) {
    const candidate = normalize(match[1] || match[2]);

    if (!candidate) continue;
    if (!isPathOrProtocolRelative(candidate)) continue;
    if (NOISE_HOST_RE.test(candidate)) continue;

    // Filter junk
    if (STATIC_ASSET_EXT.test(candidate)) continue;
    if (NUMERIC_PATH.test(candidate)) continue;
    if (CODE_SMELL.test(candidate)) continue;
    if (HARD_REJECT.test(candidate)) continue;
    if (PAGEAD_REJECT.test(candidate)) continue;
    if (TRACKING_SHAPES.test(candidate)) continue;
    if (TRACKING_KEYWORDS.test(candidate)) continue;
    if (VERSIONED_API_REJECT.test(candidate)) continue;
    if (PLUMBING_REJECT.test(candidate)) continue;

    // Keep only human pages
    if (!PAGE_EXT.test(candidate) && !looksLikePrettyContent(candidate)) continue;

    // De-dupe
    if (seen.has(candidate)) continue;
    seen.add(candidate);

    // Output item (clean schema)
    output.push({
      json: {
        output: candidate,
      },
    });
  }
}

return output;

